insert into public.recipes (id, name, category, kcal, protein, prep_min, ingredients, steps) values ('r1', 'Banana Peanut Butter Protein Pancakes', 'Breakfast', 480, 24, 15, '["2 bananas","2 eggs","1/2 cup oats","1 tbsp peanut butter","Pinch of cinnamon (optional)"]'::jsonb, '["Blend all ingredients into a smooth batter.","Cook on a non-stick pan, 2–3 min per side.","Serve with a drizzle of honey or fresh fruit."]'::jsonb) on conflict (id) do update set name = excluded.name, category = excluded.category, kcal = excluded.kcal, protein = excluded.protein, prep_min = excluded.prep_min, ingredients = excluded.ingredients, steps = excluded.steps;
insert into public.recipes (id, name, category, kcal, protein, prep_min, ingredients, steps) values ('r2', 'Cheesy Paneer Stuffed Paratha', 'Breakfast', 520, 22, 20, '["2 whole wheat dough balls","150g grated paneer","20–30g mozzarella","Onion, coriander, green chilli","Salt, pepper, chaat masala"]'::jsonb, '["Mix paneer, cheese and spices into a stuffing.","Roll dough, stuff, and re-roll into a paratha.","Cook on a hot tawa with a little ghee until golden. Serve with curd."]'::jsonb) on conflict (id) do update set name = excluded.name, category = excluded.category, kcal = excluded.kcal, protein = excluded.protein, prep_min = excluded.prep_min, ingredients = excluded.ingredients, steps = excluded.steps;
insert into public.recipes (id, name, category, kcal, protein, prep_min, ingredients, steps) values ('r3', 'Creamy Chicken Rice Bowl', 'Lunch/Dinner', 640, 45, 15, '["200g grilled chicken","1.5 cups cooked rice","Sautéed vegetables","2 tbsp hung curd","1 tsp butter","Black pepper, herbs"]'::jsonb, '["Toss cooked rice and vegetables with butter.","Top with grilled chicken and a dollop of hung curd.","Finish with black pepper and herbs."]'::jsonb) on conflict (id) do update set name = excluded.name, category = excluded.category, kcal = excluded.kcal, protein = excluded.protein, prep_min = excluded.prep_min, ingredients = excluded.ingredients, steps = excluded.steps;
